sql:
SELECT type, AVG(abv) AS avg_abv
FROM beers
GROUP BY type;

external_knowledge:
- "waves" refers to individual beers;
- "breweries casting their shadows" refers to the presence and influence of breweries in the beer industry;
- "stories shared" refers to reviews about the beers;
- "top 10 lighthouses" refers to the top 10 breweries based on average ratings and the number of beers they produce;
- "top 10 sailors" refers to the top 10 users based on average ratings and the number of reviews they have contributed;
- "most admired wave" refers to the beer with the highest overall rating;
- "whose guidance" refers to the brewery that produces the best-rated beer;
- "brightest beacon of wisdom" refers to the user with the highest average rating, indicating their insightful contributions.

sql:
SELECT COUNT(*) 
FROM beers 
WHERE type = 'IPA' AND srm BETWEEN 5.0 AND 15.0;

external_knowledge:
- "sharper edge" refers to IBU > 60;
- "stronger kick" refers to ABV > 6.5%;
- "sailing under the banners of their breweries" implies the beer and brewery names;
- "type of brews" refers to the beer type;
- "average scores in the great taste voyage" means the average ratings of the beers.

sql:
SELECT name, brewery_id, type, abv, description, image_url, ibc AS ibu, srm, brew_date, availability, serving_temperature, food_pairing
FROM beers
WHERE beer_id = 0;

external_knowledge:
- "most highly-rated brew" refers to the beer with the highest average rating; 
- "details of the brew" include its name and the name of the brewery that produces it; 
- "top average score" is the highest average rating among all beers.

sql:
SELECT DISTINCT "users"."username"
FROM "users"
JOIN "reviews" ON "users"."user_id" = "reviews"."user_id";

SELECT name, type
FROM beers
WHERE abv = (SELECT MAX(abv) FROM beers);

external_knowledge:
- "Stout" and "IPA" are popular types of beer; 
- "Average ratings" refer to the typical score given by reviewers; 
- "Highest alcohol percentages" mean the maximum ABV found among beers of the same type; 
- "Coolest serving temperatures" indicate the coldest recommended temperature at which these beers are best served.
